import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/** ====== Helpers ====== **/
const TYPE_MAP = [
    { label: "Thi công", value: "CONSTRUCTION" },
    { label: "Dịch vụ", value: "SERVICE" },
];

// Khớp enum backend (bổ sung ACTIVE + Việt hóa)
const STATUS_MAP = [
    { label: "Đang thực hiện", value: "PENDING" },
    { label: "Đang thực hiện", value: "ACTIVE" },     // ✅ thêm
    { label: "Hoàn tất", value: "COMPLETED" },
    { label: "Hủy", value: "CANCELLED" },
];

const findLabel = (list, v) => list.find((x) => x.value === v)?.label || v || "-";
const fmtMoney = (n) => (n ?? 0).toLocaleString("vi-VN", { maximumFractionDigits: 0 });
const parseMoney = (s) => {
    if (typeof s === "number") return s;
    if (!s) return 0;
    const digits = String(s).replace(/[^\d]/g, "");
    return Number(digits || 0);
};

const toISO = (d) => {
    if (!d) return "";
    if (/^\d{4}-\d{2}-\d{2}$/.test(d)) return d;
    const m = String(d).match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) return `${m[3]}-${m[2]}-${m[1]}`;
    try {
        const dt = new Date(d);
        if (!isNaN(dt)) return dt.toISOString().slice(0, 10);
    } catch {}
    return "";
};

function useDebounce(v, delay = 450) {
    const [val, setVal] = useState(v);
    useEffect(() => {
        const t = setTimeout(() => setVal(v), delay);
        return () => clearTimeout(t);
    }, [v, delay]);
    return val;
}

const hasRole = (user, roles) => {
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object") {
            ["role", "name", "authority", "code"].forEach((k) => x[k] && S.add(String(x[k]).toUpperCase()));
            ["roles", "authorities"].forEach((k) => add(x[k]));
        }
    };
    add(user?.role);
    add(user?.roles);
    add(user?.authorities);
    return roles.some((r) => S.has(r));
};

function isSaleUser(u) {
    const bag = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return bag.add(x.toUpperCase());
        if (typeof x === "object") {
            ["role", "name", "authority", "code"].forEach((k) => u[k] && bag.add(String(u[k]).toUpperCase()));
            ["roles", "authorities"].forEach((k) => add(u[k]));
        }
    };
    add(u.roles);
    add(u.authorities);
    add(u.role);
    for (const v of bag) if (v.includes("SALE")) return true;
    return false;
}

// Badge màu theo trạng thái (VN)
const statusBadgeClass = (v) => {
    const s = String(v || "").toUpperCase();
    if (s === "COMPLETED") return "bg-emerald-100 text-emerald-700";
    if (s === "CANCELLED") return "bg-rose-100 text-rose-700";
    // PENDING / ACTIVE / mặc định
    return "bg-amber-100 text-amber-700";
};

/** ====== Page ====== **/
export default function Contracts() {
    const { user } = useAuth();
    const canEdit = hasRole(user, ["ADMIN"]); // chỉ ADMIN được thao tác

    const [rows, setRows] = useState([]);
    const [customers, setCustomers] = useState([]);
    const [sales, setSales] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q);
    const [type, setType] = useState("");
    const [status, setStatus] = useState("");
    const [from, setFrom] = useState("");
    const [to, setTo] = useState("");

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);

    const [form, setForm] = useState({
        contractCode: "",
        title: "",
        customerId: "",
        salesId: "",
        totalAmount: "",
        signedDate: "",
        dueDate: "",
        contractType: "CONSTRUCTION",
        status: "PENDING",
    });

    // NEW: chia đợt
    const [splitsOpen, setSplitsOpen] = useState(false);
    const [installments, setInstallments] = useState([]); // [{no, amount, planDate, note}]

    useEffect(() => {
        loadAll();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [dq, type, status, from, to]);

    useEffect(() => {
        loadSales();
    }, []);

    async function loadAll() {
        setLoading(true);

        const params = {
            q: dq || undefined,
            type: type || undefined,
            status: status || undefined,
            from: toISO(from) || undefined,
            to: toISO(to) || undefined,
            page: 0,
            size: 50,
            sort: "id,desc",
        };

        const [contractsRes, customersRes] = await Promise.allSettled([
            api.get("/api/contracts", { params }),
            api.get("/api/customers", { params: { page: 0, size: 100, sort: "name,asc" } }),
        ]);

        if (contractsRes.status === "fulfilled") {
            const data = contractsRes.value?.data;
            const list = Array.isArray(data) ? data : data?.content || [];
            setRows(
                list.map((x) => ({
                    id: x.id,
                    contractCode: x.contractCode,
                    title: x.title,
                    contractType: x.contractType,
                    customerId: x.customerId,
                    customerName: x.customerName,
                    salesId: x.salesId || x.saleId || x.sales?.id || x.sale?.id,
                    salesName:
                        x.salesName ||
                        x.saleName ||
                        x.sales?.fullName ||
                        x.sales?.name ||
                        x.sales?.username ||
                        x.sale?.fullName ||
                        x.sale?.name ||
                        x.sale?.username ||
                        "",
                    signedDate: x.signedDate,
                    dueDate: x.dueDate,
                    totalAmount: x.totalAmount,
                    paidAmount: x.paidAmount,
                    remainingAmount: x.remainingAmount,
                    status: x.status,
                }))
            );
        } else {
            console.warn("Contracts load failed:", contractsRes.reason);
            setRows([]);
        }

        if (customersRes.status === "fulfilled") {
            const data = customersRes.value?.data;
            const custList = Array.isArray(data) ? data : data?.content || [];
            setCustomers(custList.map((c) => ({ id: c.id, name: c.name })));
        } else {
            console.warn("Customers load failed:", customersRes.reason);
        }

        setLoading(false);
    }

    async function loadSales() {
        try {
            const tries = [
                { url: "/api/users", params: { page: 0, size: 1000, sort: "id,asc" } },
                { url: "/api/users", params: { role: "SALES", page: 0, size: 1000 } },
                { url: "/api/users/sales", params: {} },
            ];
            let users = [];
            for (const t of tries) {
                try {
                    const { data } = await api.get(t.url, { params: t.params });
                    users = Array.isArray(data) ? data : data?.content || [];
                    if (users.length) break;
                } catch {}
            }
            const saleUsers = users.filter(isSaleUser);
            setSales(
                saleUsers.map((u) => ({
                    id: u.id,
                    name: u.fullName || u.name || u.username || `User #${u.id}`,
                }))
            );
        } catch (e) {
            console.warn("Không lấy được danh sách SALE:", e);
            setSales([]);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            contractCode: autoCode(),
            title: "",
            customerId: "",
            salesId: "",
            totalAmount: "",
            signedDate: todayStr(),
            dueDate: "",
            contractType: "CONSTRUCTION",
            status: "PENDING",
        });
        setSplitsOpen(false);
        setInstallments([]);
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            contractCode: row.contractCode || "",
            title: row.title || "",
            customerId: row.customerId || "",
            salesId: row.salesId ? String(row.salesId) : "",
            totalAmount: fmtMoney(row.totalAmount || 0),
            signedDate: toISO(row.signedDate) || "",
            dueDate: toISO(row.dueDate) || "",
            contractType: row.contractType || "CONSTRUCTION",
            status: row.status || "PENDING",
        });
        setSplitsOpen(false);
        setInstallments([]);
        setShow(true);
    }

    function clean(obj) {
        const out = {};
        for (const [k, v] of Object.entries(obj)) {
            if (v !== undefined) out[k] = v;
        }
        return out;
    }

    function spreadEven(total, n) {
        const t = parseMoney(total);
        const base = Math.floor(t / n);
        const arr = Array(n).fill(base);
        let rem = t - base * n;
        for (let i = 0; i < n && rem > 0; i++, rem--) arr[i] += 1;
        return arr;
    }

    async function save(e) {
        e.preventDefault();
        try {
            const saleIdNum = form.salesId ? Number(form.salesId) : undefined;

            if (editing) {
                // UPDATE
                const payloadRaw = {
                    contractCode: form.contractCode?.trim() || null,
                    title: form.title?.trim() || null,
                    contractType: form.contractType || null,
                    signedDate: toISO(form.signedDate) || null,
                    dueDate: toISO(form.dueDate) || null,
                    totalAmount: parseMoney(form.totalAmount),
                    status: form.status || null,
                    salesId: saleIdNum,
                    saleId: saleIdNum,
                };
                const payload = clean(payloadRaw);

                try {
                    await api.patch(`/api/contracts/${editing.id}`, payload);
                } catch {
                    await api.put(`/api/contracts/${editing.id}`, payload);
                }
            } else {
                // CREATE (1) tạo HĐ
                const saleIdNum2 = form.salesId ? Number(form.salesId) : undefined;
                const payloadCreate = clean({
                    contractCode: form.contractCode?.trim() || undefined,
                    title: form.title?.trim(),
                    contractType: form.contractType,
                    customerId: Number(form.customerId),
                    signedDate: toISO(form.signedDate) || null,
                    dueDate: toISO(form.dueDate) || null,
                    totalAmount: parseMoney(form.totalAmount),
                    salesId: saleIdNum2,
                    saleId: saleIdNum2,
                });

                const res = await api.post("/api/contracts", payloadCreate);
                const newId = res?.data?.id ?? res?.data;

                // (2) nếu bật chia đợt -> gọi bulk
                if (splitsOpen && installments.length && newId) {
                    const bulkBody = {
                        items: installments.map((it) => ({
                            installmentNo: it.no,
                            amount: parseMoney(it.amount),
                            planDate: toISO(it.planDate) || null,
                            note: it.note?.trim() || null,
                        })),
                    };
                    await api.post(`/api/contracts/${newId}/payments/bulk`, bulkBody);
                }
            }

            setShow(false);
            await loadAll();
        } catch (err) {
            console.error("Save contract error:", err?.response || err);
            const data = err?.response?.data;
            let msg = data?.message || data?.error || (typeof data === "string" ? data : "") || "Lưu hợp đồng thất bại";
            try {
                if (!msg && data) msg = JSON.stringify(data);
            } catch {}
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xóa hợp đồng ${row.contractCode}?`)) return;
        try {
            await api.delete(`/api/contracts/${row.id}`);
            await loadAll();
        } catch (err) {
            const res = err?.response;
            const data = res?.data;
            const msg =
                data?.message || data?.error || (typeof data === "string" ? data : "") || `Xóa hợp đồng thất bại (HTTP ${res?.status || "?"})`;
            console.error("Delete contract error:", res || err);
            alert(msg);
        }
    }

    const customerOptions = useMemo(() => customers.map((c) => ({ value: String(c.id), label: c.name })), [customers]);
    const salesOptions = useMemo(() => sales.map((s) => ({ value: String(s.id), label: s.name })), [sales]);

    return (
        <div className="space-y-8">
            {/* Toolbar */}
            <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold text-slate-900">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Tìm kiếm, lọc và quản lý hợp đồng.</p>
                </div>

                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="w-80 px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            placeholder="Mã/tiêu đề/KH/NVKD…"
                            value={q}
                            onChange={(e) => setQ(e.target.value)}
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Loại HĐ</label>
                        <select className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={type} onChange={(e) => setType(e.target.value)}>
                            <option value="">Tất cả</option>
                            {TYPE_MAP.map((t) => (
                                <option key={t.value} value={t.value}>
                                    {t.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                        <select className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={status} onChange={(e) => setStatus(e.target.value)}>
                            <option value="">Tất cả</option>
                            {STATUS_MAP.map((s) => (
                                <option key={s.value} value={s.value}>
                                    {s.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Từ ngày</label>
                        <input type="date" className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={from} onChange={(e) => setFrom(e.target.value)} />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Đến ngày</label>
                        <input type="date" className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" value={to} onChange={(e) => setTo(e.target.value)} />
                    </div>

                    {canEdit && (
                        <button onClick={openCreate} className="ml-auto px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                            Thêm hợp đồng
                        </button>
                    )}
                </div>
            </div>

            {/* List */}
            <div className="grid grid-cols-1 2xl:grid-cols-2 gap-8">
                {loading ? (
                    <div className="col-span-full text-slate-500">Đang tải…</div>
                ) : rows.length === 0 ? (
                    <div className="col-span-full text-slate-500">Không có hợp đồng phù hợp</div>
                ) : (
                    rows.map((c) => (
                        <div key={c.id} className="rounded-3xl border border-indigo-100 bg-white p-6 shadow-md hover:shadow-lg transition h-full flex flex-col">
                            <div className="flex items-start justify-between gap-4">
                                <div className="text-lg md:text-xl font-semibold text-slate-900 truncate">
                                    {c.contractCode || "(Không mã)"}
                                </div>
                                {/* ✅ Badge trạng thái tiếng Việt + màu theo state */}
                                <span className={`text-xs px-2 py-0.5 rounded-full shrink-0 ${statusBadgeClass(c.status)}`}>
                  {findLabel(STATUS_MAP, c.status)}
                </span>
                            </div>

                            <div className="mt-2 text-base text-slate-600">{c.title || "—"}</div>
                            <div className="mt-1 text-sm text-slate-500">
                                {findLabel(TYPE_MAP, c.contractType)} • Kh: {c.customerName || "—"}
                                {c.salesName ? <> • Sale: {c.salesName}</> : null}
                            </div>

                            <div className="mt-4 grid grid-cols-1 sm:grid-cols-3 gap-3">
                                <div className="rounded-xl bg-slate-50 px-4 py-3">
                                    <div className="text-xs text-slate-500">Giá trị</div>
                                    <div className="font-semibold tabular-nums tracking-tight text-base whitespace-nowrap">
                                        {fmtMoney(c.totalAmount)} đ
                                    </div>
                                </div>
                                <div className="rounded-xl bg-slate-50 px-4 py-3">
                                    <div className="text-xs text-slate-500">Đã thu</div>
                                    <div className="font-semibold tabular-nums tracking-tight text-base whitespace-nowrap">
                                        {fmtMoney(c.paidAmount)} đ
                                    </div>
                                </div>
                                <div className="rounded-xl bg-slate-50 px-4 py-3">
                                    <div className="text-xs text-slate-500">Còn lại</div>
                                    <div className="font-semibold tabular-nums tracking-tight text-base whitespace-nowrap">
                                        {fmtMoney(c.remainingAmount)} đ
                                    </div>
                                </div>
                            </div>

                            <div className="mt-5 flex-1" />
                            <div className="mt-3 flex justify-end gap-2">
                                {canEdit ? (
                                    <>
                                        <button onClick={() => openEdit(c)} className="px-3 py-1.5 rounded-lg bg-indigo-50 text-indigo-700 hover:bg-indigo-100">
                                            Sửa
                                        </button>
                                        <button onClick={() => remove(c)} className="px-3 py-1.5 rounded-lg bg-rose-50 text-rose-700 hover:bg-rose-100">
                                            Xóa
                                        </button>
                                    </>
                                ) : (
                                    <span className="text-slate-400 text-sm">Chỉ xem</span>
                                )}
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-6">
                    <div className="w-full max-w-4xl rounded-3xl bg-white shadow-2xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="text-lg font-semibold">{editing ? "Sửa hợp đồng" : "Thêm hợp đồng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Mã hợp đồng</label>
                                <input
                                    value={form.contractCode}
                                    onChange={(e) => setForm((f) => ({ ...f, contractCode: e.target.value }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                    placeholder="VD: HD-20250828-9154"
                                />
                            </div>

                            {!editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Khách hàng</label>
                                    <select
                                        value={form.customerId}
                                        onChange={(e) => setForm((f) => ({ ...f, customerId: e.target.value }))}
                                        className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                        required
                                    >
                                        <option value="">— Chọn khách hàng —</option>
                                        {customerOptions.map((opt) => (
                                            <option key={opt.value} value={opt.value}>
                                                {opt.label}
                                            </option>
                                        ))}
                                    </select>
                                </div>
                            )}

                            <div>
                                <label className="text-sm text-slate-600">Phụ trách (Sale)</label>
                                <select
                                    value={form.salesId}
                                    onChange={(e) => setForm((f) => ({ ...f, salesId: e.target.value }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                >
                                    <option value="">— Chọn sale —</option>
                                    {salesOptions.map((opt) => (
                                        <option key={opt.value} value={opt.value}>
                                            {opt.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Tiêu đề</label>
                                <input
                                    value={form.title}
                                    onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                    placeholder="VD: Thi công nhà xưởng B - Phase 2"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Giá trị (đ)</label>
                                <input
                                    inputMode="numeric"
                                    value={form.totalAmount}
                                    onChange={(e) => setForm((f) => ({ ...f, totalAmount: fmtMoney(parseMoney(e.target.value)) }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm tabular-nums"
                                    placeholder="VD: 2.000.000.000"
                                    required
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày ký</label>
                                <input
                                    type="date"
                                    value={form.signedDate}
                                    onChange={(e) => setForm((f) => ({ ...f, signedDate: e.target.value }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                    required
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày hết hạn</label>
                                <input
                                    type="date"
                                    value={form.dueDate}
                                    onChange={(e) => setForm((f) => ({ ...f, dueDate: e.target.value }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                <select
                                    value={form.contractType}
                                    onChange={(e) => setForm((f) => ({ ...f, contractType: e.target.value }))}
                                    className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                >
                                    {TYPE_MAP.map((t) => (
                                        <option key={t.value} value={t.value}>
                                            {t.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Trạng thái</label>
                                    <select
                                        value={form.status}
                                        onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                        className="w-full px-4 py-2.5 rounded-xl border border-indigo-100 bg-white shadow-sm"
                                    >
                                        {STATUS_MAP.map((s) => (
                                            <option key={s.value} value={s.value}>
                                                {s.label}
                                            </option>
                                        ))}
                                    </select>
                                </div>
                            )}

                            {/* ===== Chia đợt thanh toán (chỉ khi tạo mới) ===== */}
                            {!editing && (
                                <div className="md:col-span-2 border rounded-xl p-3 border-indigo-100">
                                    <div className="flex items-center justify-between">
                                        <div className="font-medium">Chia đợt thanh toán</div>
                                        <button type="button" className="text-indigo-600 text-sm" onClick={() => setSplitsOpen((v) => !v)}>
                                            {splitsOpen ? "Ẩn" : "Bật"}
                                        </button>
                                    </div>

                                    {splitsOpen && (
                                        <div className="mt-3 space-y-3">
                                            <div className="flex items-center gap-3">
                                                <label className="text-sm w-40">Số đợt</label>
                                                <input
                                                    type="number"
                                                    min={1}
                                                    className="px-3 py-2 rounded-lg border border-indigo-100"
                                                    placeholder="VD: 3"
                                                    onChange={(e) => {
                                                        const n = Math.max(1, Number(e.target.value || 1));
                                                        const amounts = spreadEven(form.totalAmount, n);
                                                        const today = todayStr();
                                                        setInstallments(
                                                            Array.from({ length: n }).map((_, i) => ({
                                                                no: i + 1,
                                                                amount: fmtMoney(amounts[i]),
                                                                planDate: today,
                                                                note: "",
                                                            }))
                                                        );
                                                    }}
                                                />
                                                <button
                                                    type="button"
                                                    className="px-2 py-1 rounded bg-slate-100"
                                                    onClick={() => {
                                                        if (!installments.length) {
                                                            const amounts = spreadEven(form.totalAmount, 2);
                                                            const today = todayStr();
                                                            setInstallments([
                                                                { no: 1, amount: fmtMoney(amounts[0]), planDate: today, note: "" },
                                                                { no: 2, amount: fmtMoney(amounts[1]), planDate: today, note: "" },
                                                            ]);
                                                        }
                                                    }}
                                                >
                                                    Chia đều
                                                </button>
                                            </div>

                                            {installments.length > 0 && (
                                                <div className="overflow-auto">
                                                    <table className="min-w-full text-sm">
                                                        <thead className="bg-indigo-50">
                                                        <tr>
                                                            <th className="px-3 py-2 text-left w-20">Đợt</th>
                                                            <th className="px-3 py-2 text-left w-48">Số tiền (đ)</th>
                                                            <th className="px-3 py-2 text-left w-48">Ngày dự kiến</th>
                                                            <th className="px-3 py-2 text-left">Ghi chú</th>
                                                            <th className="px-3 py-2 text-right w-24"> </th>
                                                        </tr>
                                                        </thead>
                                                        <tbody className="divide-y">
                                                        {installments.map((it, idx) => (
                                                            <tr key={idx}>
                                                                <td className="px-3 py-2">{it.no}</td>
                                                                <td className="px-3 py-2">
                                                                    <input
                                                                        className="w-44 px-2 py-1 rounded border border-indigo-100 tabular-nums"
                                                                        value={it.amount}
                                                                        onChange={(e) =>
                                                                            setInstallments((arr) =>
                                                                                arr.map((x, i) =>
                                                                                    i === idx ? { ...x, amount: fmtMoney(parseMoney(e.target.value)) } : x
                                                                                )
                                                                            )
                                                                        }
                                                                    />
                                                                </td>
                                                                <td className="px-3 py-2">
                                                                    <input
                                                                        type="date"
                                                                        className="w-44 px-2 py-1 rounded border border-indigo-100"
                                                                        value={it.planDate}
                                                                        onChange={(e) =>
                                                                            setInstallments((arr) =>
                                                                                arr.map((x, i) => (i === idx ? { ...x, planDate: e.target.value } : x))
                                                                            )
                                                                        }
                                                                    />
                                                                </td>
                                                                <td className="px-3 py-2">
                                                                    <input
                                                                        className="w-full px-2 py-1 rounded border border-indigo-100"
                                                                        value={it.note}
                                                                        onChange={(e) =>
                                                                            setInstallments((arr) =>
                                                                                arr.map((x, i) => (i === idx ? { ...x, note: e.target.value } : x))
                                                                            )
                                                                        }
                                                                    />
                                                                </td>
                                                                <td className="px-3 py-2 text-right">
                                                                    <button
                                                                        type="button"
                                                                        className="px-2 py-1 rounded bg-rose-50 text-rose-700"
                                                                        onClick={() => setInstallments((arr) => arr.filter((_, i) => i !== idx))}
                                                                    >
                                                                        Xóa
                                                                    </button>
                                                                </td>
                                                            </tr>
                                                        ))}
                                                        </tbody>
                                                    </table>

                                                    {/* Tổng dự kiến */}
                                                    <div className="text-right mt-2 text-sm">
                                                        Tổng dự kiến:{" "}
                                                        <span className="font-semibold">
                              {fmtMoney(installments.reduce((s, x) => s + parseMoney(x.amount), 0))} đ
                            </span>
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            )}

                            <div className="md:col-span-2 flex justify-end gap-2 pt-2">
                                <button type="button" className="px-3.5 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={() => setShow(false)}>
                                    Hủy
                                </button>
                                <button className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

function todayStr() {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
}
function autoCode() {
    const d = new Date();
    const seg = `${d.getFullYear()}${String(d.getMonth() + 1).padStart(2, "0")}${String(
        d.getDate(),
    ).padStart(2, "0")}-${Math.floor(1000 + Math.random() * 9000)}`;
    return `HD-${seg}`;
}
